from __future__ import annotations

from typing import Any


def _pack(category: str, rows: list[tuple[str, str, list[str]]]) -> list[dict[str, Any]]:
    packed = []
    for idx, (question, answer, formulas) in enumerate(rows, start=1):
        packed.append(
            {
                "id": f"{category}-{idx}",
                "category": category,
                "question": question,
                "answer": answer,
                "formulas": formulas,
            }
        )
    return packed


